func validateRawJSON(value json.RawMessage) bool {
	if len(value) == 0 {
		return true
	}
	return json.Valid(value)
}

func containsString(values []string, value string) bool {
	for _, item := range values {
		if item == value {
			return true
		}
	}
	return false
}
